sql:
SELECT company_name, symbol
FROM stocks
ORDER BY company_name;

SELECT company_name
FROM stocks
WHERE industry = 'Technology';

SELECT MAX(close_price) AS highest_closing_price
FROM closing_prices
WHERE movement_id = 1;

SELECT industry, AVG(market_cap) AS average_market_cap
FROM stocks
GROUP BY industry;

SELECT AVG(high_until_expiry - low_until_expiry) AS average_price_movement
FROM expiry_details
WHERE days_until_expiry BETWEEN 10 AND 20;

SELECT AVG(market_cap) AS average_market_cap
FROM stocks
WHERE industry = 'Technology';

external_knowledge:
- 'last year' refers to the year 2023;
- 'biggest price swings' refers to the maximum price movements;
- 'solid level of confidence' means a confidence level of 80 or above;

sql:
SELECT COUNT(analyst_id) 
FROM analysts 
WHERE expertise_area = 'Technology';

external_knowledge:
